import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface CombatPopupData {
    userId: number;
    damage: number;
    isMiss: boolean;
    isKo: boolean;
    isCrit: boolean;
    isStun: boolean;
}

export class CombatPopupParser implements IMessageParser {
    private _data: CombatPopupData | null = null;

    public flush(): boolean {
        this._data = null;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        this._data = {
            userId: wrapper.readInt(),
            damage: wrapper.readInt(),
            isMiss: wrapper.readBoolean(),
            isKo: wrapper.readBoolean(),
            isCrit: wrapper.readBoolean(),
            isStun: wrapper.readBoolean()
        };

        return true;
    }

    public get data(): CombatPopupData | null {
        return this._data;
    }
}